effect.shader:

vec4 xstreak() {
    float texelSize = 1.0 / acScreenSize.x;
    float dist = strength * 0.05;
    int nSamples = int(clamp(dist/texelSize,1.01,100.01));
    vec4 c = vec4(0.);
    for( int i=1; i<nSamples; i++ ) {
        float offset = dist * (float(i)/float(nSamples-1) - 0.5);
        vec2 sampleCoord = acScreenNorm + vec2(offset,0.);
        vec4 tc;
        if(acPass==1) {
            tc = texture2DCv( inputImg.texture,sampleCoord);
        } else {
            tc = texture2DCv( hstreak.texture,sampleCoord);
        }
        if( offset < 0. ) {
            c = c * (1.-tc.a) + tc;
        } else {
            c = tc * (1.-c.a) + c;
        }
    }
    return c;
}

vec4 ystreak() {
    float texelSize = 1.0 / acScreenSize.y;
    float dist = strength * 0.05;
    int nSamples = int(clamp(dist/texelSize,1.01,100.01));
    vec4 c = vec4(0.);
    for( int i=1; i<nSamples; i++ ) {
        float offset = dist * (float(i)/float(nSamples-1) - 0.5);
        vec2 sampleCoord = acScreenNorm + vec2(0.,offset);
        vec4 tc;
        if(acPass==1) {
            tc = texture2DCv( inputImg.texture,sampleCoord);
        } else {
            tc = texture2DCv( hstreak.texture,sampleCoord);
        }
        if( offset < 0. ) {
            c = c * (1.-tc.a) + tc;
        } else {
            c = tc * (1.-c.a) + c;
        }
    }
    return c;
}

vec4 composite( vec4 a, vec4 b) {
    return a * (1. - b.a) + b;
}

void main() {
    if( maskToLayer ) {
        if( acPass==1 || acPass==2 ) {
            gl_FragColor = vec4(0.);
        } else {
            vec4 blur = texture2DCv(hblur.texture, acScreenNorm.st);
            vec4 base = texture2DCv(inputImg.texture, acScreenNorm.st);
            float dd = 0.05 / ((1.+strength)*(1.+strength));
            gl_FragColor = base * smoothstep(0.5-dd,0.5+dd,blur.a);
        }
    } else if( acPass==1 || acPass==2 ) {
        vec4 c1 = xstreak();
        vec4 c2 = ystreak();
        vec4 base = texture2DCv(inputImg.texture, acScreenNorm);
        gl_FragColor = composite(composite(c1,c2),base);
    } else {
        vec4 blur = texture2DCv(hblur.texture, acScreenNorm);
        vec4 base = texture2DCv(vstreak.texture, acScreenNorm);
        float dd = 0.05 / ((1.+strength)*(1.+strength));
        float p = smoothstep(0.5-dd,0.5+dd,blur.a);
        gl_FragColor = base * p;
    }
}
